	require.NoError(t, err)
	require.NoError(t, json.Unmarshal(rawManifest, &manifest))
	assert.Equal(t, "native-review-1", manifest.SessionID)
	assert.Equal(t, strings.TrimSpace(head), manifest.ResultRev)
}

