	evidenceDir := filepath.Join(root, ".ddx", "executions", "20260417T000000-testattempt", "embedded")
	if err := os.MkdirAll(evidenceDir, 0o755); err != nil {
		t.Fatalf("mkdir evidence: %v", err)
